  "task_summary": "Implement a Least Recently Used (LRU) cache with get and put operations",
  "approach": "Create an LRU cache using a dictionary and a min-heap to maintain order of insertion and remove least recently used items.",
  "code": "import heapq
class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {} 
        self.heap = []
    def get(self, key: int) -> int or None:
        if key in self.cache:
            # Move the item to the end of the heap
            heapq.heappushpop(self.heap, (key, self.cache[key]))
            return self.cache[key]
        else:
            return None
    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            # Update existing item's value and move it to the end of the heap
            heapq.heapreplace(self.heap, (key, value))
            self.cache[key] = value
        else:
            # If cache is full, remove the least recently used item
            if len(self.heap) > self.capacity:
                min_key = heapq.heappop(self.heap)[0]
                del self.cache[min_key]
            self.cache[key] = value
    def __str__(self):
        return str(self.cache)
",
