{
  "task_summary": "Implement a lightweight job scheduler with priorities, retry limits, and failure callbacks using only standard library capabilities in Node.js.",
  "approach": "Use `setInterval` to schedule tasks based on priority and `try...catch` blocks for retries and error handling.",
  "code": "const { setImmediate } = require('timers');

class JobScheduler {
  constructor() { this.tasks = []; }

  add(priority, callback) {
    const newTask = () => { try { callback(); } catch (error) { console.error(`Job failed for task with priority ${priority}: ${error.message}`); } };

    if (this.tasks.length >= Math.max(1, priority + 1)) return; // Do not add a new task if we're at the maximum priority limit.

    setImmediate(newTask, priority);
    this.tasks.push(newTask); // Schedule the new task to run after the current one finishes.
  }

  remove(priority) {
    const index = this.tasks.findIndex(task => task.priority === priority);
    if (index !== -1) { this.tasks.splice(index, 1); } // Remove the task from the array if it exists.
  }
}

const scheduler = new JobScheduler();

scheduler.add(5, () => console.log('Running job 5'));
scheduler.add(3, () => console.log('Running job 3'));
scheduler.add(2, () => console.log('Running job 2'));
scheduler.remove(4); // Attempt to remove a non-existent priority.

console.log(scheduler.tasks); // Output: [ function() { try { console.log('Running job 5'); } catch (error) { console.error(`Job failed for task with priority ${3}: ${error.message}`); } }, function() { try { console.log('Running job 3'); } catch (error) { console.error(`Job failed for task with priority ${4}: ${error.message}`); } }, function() { try { console.log('Running job 2'); } catch (error) { console.error(`Job failed for task with priority ${2}: ${error.message}`); } }]
",
