const logger = createLogger({ level: 'info', format: 'sddd [${level}] [${date}]: ${message}' });
const jobsQueue = new Queue(); // Initialize the queue
const retryQueue = new Queue(); // Initialize the retry queue
function scheduleJob(name, priority, job) { 
  jobsQueue.add({ name, priority, job }); 
} // Schedule a job by adding it to the queue
function retryJob(name, retries, delay) { 
  retryQueue.add({ name, retries, delay }); 
} // Retry a previously scheduled job with delays until all retries have been completed
function completeJob(name) { 
  return jobsQueue.dequeue().jobCompleted; 
}
function cancelJob(name) { 
  return jobsQueue.remove(name); 
}
// Example sequence showing how higher-priority jobs run first
scheduleJob('name', 1, () => { logger.info(`Task ${name} has been scheduled for higher priority`); });
jobsQueue.add({ name: 'job1', priority: 2, job: () => { logger.info(`Task ${name} has been executed`) }});
jobsQueue.add({ name: 'job2', priority: 3, job: () => { logger.info(`Task ${name} has been re-executed`) }});
runtimeError jobsQueue.run(); // Wait until all jobs have completed
console.log(completeJob('job1')); // Output: true (true is returned to indicate that the task was successfully completed)
jobsQueue.cancel('job2'); // Cancel job2
console.log(completeJob('job2')); // Output: false (false indicates that there are no more job 2s scheduled, but if retrying later, it will run immediately)
jobsQueue.run(); // Continue to wait until all jobs have completed
logger.info(`All tasks have been completed`);
",
