  "task_summary": "Create a function to transform raw customer records into a canonical schema for normalization and validation.",
  "approach": "Parse each record, standardize fields, clean up data, and validate against the specified constraints.",
  "code": "def normalize_customer_records(raw_data):
    def sanitize_name(name):
        return name.replace(',', '')
    def sanitize_email(email):
        if '[' in email:
            return email
        else:
            return email.lower()
    def sanitize_phone(phone):
        try:
            phone = int(phone)
            return str(phone)
        except ValueError:
            return None
    def sanitize_country(country):
        # Assume common country codes for simplicity
        if 'usa' in country.lower():
            return 'USA'
        else:
            return country.lower()
    normalized_records = [sanitize_name(record['name']), sanitize_email(record['email']), sanitize_phone(record['phone']), sanitize_country(record['country']) for record in raw_data]
    return normalized_records
