  "code": "def validate_api_payloads(payloads):
    valid = []
    for payload in payloads:
        try:
            # Validate the payload
            if not isinstance(payload, dict):
                raise ValueError("Invalid payload type: {payload}")
            if not all(isinstance(key, str) and key != '' for key in payload.keys()):
                raise ValueError("All keys must be strings and non-empty")
            # Perform business validation
            if 'name' not in payload or len(payload['name']) < 3:
                raise ValueError("Name must be at least 3 characters long")
            if 'age' not in payload or payload['age'] < 18:
                raise ValueError("Age must be at least 18 years old")
        except ValueError as e:
            valid.append(e)
    return valid
